Here's the refactored version using async/await:

```javascript
module.exports = async function handler(req, res) {
  try {
    const results = await db.query('SELECT * FROM users');
    res.json(results);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
};
```
